_ATTR = (
    'fill="none" stroke="currentColor" stroke-width="2" '
    'stroke-linecap="round" stroke-linejoin="round"'
)


def sprite_svg() -> str:
    parts = [
        '<svg class="svg-sprite" xmlns="http://www.w3.org/2000/svg" aria-hidden="true">'
    ]
    for name, paths in _ICONS.items():
        parts.append(
            f'<symbol id="{name}" viewBox="0 0 24 24" {_ATTR}>{paths}</symbol>'
        )
    parts.append("</svg>")
    return "".join(parts)
